function forEvents(t,e){t.split(/\s+/).forEach(t=>{e(t)})}export default class MicroEvent{constructor(){this._events={}}on(t,s){forEvents(t,t=>{const e=this._events[t]||[];e.push(s),this._events[t]=e})}off(t,s){var n=arguments.length;0===n?this._events={}:forEvents(t,t=>{if(1===n)delete this._events[t];else{const e=this._events[t];void 0!==e&&(e.splice(e.indexOf(s),1),this._events[t]=e)}})}trigger(t,...s){var n=this;forEvents(t,t=>{const e=n._events[t];void 0!==e&&e.forEach(t=>{t.apply(n,s)})})}}